patch:
--- a/decoder.vhdl
+++ b/decoder.vhdl
@@ -1,16 +1,16 @@
 library ieee;
 use ieee.std_logic_1164.all;

 entity decoder_3to8 is
   port (
     input_sel : in std_logic_vector(2 downto 0);
     enable_sig : in std_logic;
     decoded_out : out std_logic_vector(7 downto 0)
   );
 end decoder_3to8;

 architecture rtl of decoder_3to8 is
 begin
-  process(input_sel)
+  process(input_sel, enable_sig)
   begin
     if (enable_sig = '1') then
       case input_sel is
         when "000" => decoded_out <= "00000001";
         when "001" => decoded_out <= "00000010";
         when "010" => decoded_out <= "00000100";
         when "011" => decoded_out <= "00001000";
         when "100" => decoded_out <= "00010000";
         when "101" => decoded_out <= "00100000";
         when "110" => decoded_out <= "01000000";
         when "111" => decoded_out <= "10000000";
         when others => decoded_out <= "00000000";
       end case;
     else
       decoded_out <= "00000000";
     end if;
   end process;
 end rtl;

